@Component({
  selector: 'app-main',
  template: `
    <ion-content [innerHTML]="mainContent"></ion-content>
  `
})
export class MainPage implements OnInit {
  mainContent: string = '';

  constructor(
    private backendService: BackendService,
    private cacheService: CacheService
  ) {}

  async ngOnInit() {
    // Attempt to load cached content first
    const cachedData = await this.cacheService.getCachedContent('mainPage');
    if (cachedData && this.cacheService.isCacheValid(cachedData.timestamp)) {
      this.mainContent = cachedData.content;
    } else {
      // Fetch fresh content from backend
      const data = await this.backendService.getMainPageContent();
      this.mainContent = data.content;
      // Save to cache with timestamp
      await this.cacheService.cacheContent('mainPage', {
        content: data.content,
        timestamp: Date.now()
      });
    }
  }
}
